function solve(s) {
    const seen = new Set();
    const segments = [];
    let i = 0;
    let current = '';

    while (i < s.length) {
        while (i < s.length) {
            current += s[i];
            if (!seen.has(current)) {
                break;
            } else {
                i += 1;
            }
